const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// --- Security middleware ---

// Set secure HTTP headers (XSS, clickjacking, MIME-sniffing protection, etc.)
app.use(helmet());

// Parse JSON bodies with a size limit to prevent large-payload DoS
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Rate limiting — allow 100 requests per 15-minute window per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Remove the X-Powered-By header so attackers can't fingerprint the framework
app.disable('x-powered-by');

// --- Routes ---

app.get('/health', (_req, res) => {
  // Return minimal info — avoid leaking internals
  res.json({ status: 'ok' });
});

app.get('/users', (req, res) => {
  // Input validation: sanitize and validate query parameters
  const limit = Math.min(Math.max(parseInt(req.query.limit, 10) || 10, 1), 100);
  const offset = Math.max(parseInt(req.query.offset, 10) || 0, 0);

  // In production, this would come from a database with parameterized queries
  const users = [
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ];

  // Apply pagination
  const paginatedUsers = users.slice(offset, offset + limit);

  res.json({
    data: paginatedUsers,
    pagination: { limit, offset, total: users.length },
  });
});

// --- 404 handler for undefined routes ---
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global error handler ---
// Must have 4 parameters so Express recognizes it as an error handler
app.use((err, _req, res, _next) => {
  // Log the full error server-side for debugging
  console.error('Unhandled error:', err);

  // Never expose stack traces or internal details to the client
  const statusCode = err.statusCode || 500;
  res.status(statusCode).json({
    error: statusCode === 500 ? 'Internal server error' : err.message,
  });
});

// --- Server startup ---
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

