const express = require('express');
const helmet = require('helmet');

const app = express();
const PORT = process.env.PORT || 3000;

// --- Security Middleware ---
// helmet sets secure HTTP headers (X-Content-Type-Options, X-Frame-Options, etc.)
app.use(helmet());

// Parse JSON bodies with a strict size limit to prevent large-payload DoS
app.use(express.json({ limit: '10kb' }));

// Disable the X-Powered-By header so attackers can't fingerprint the framework
app.disable('x-powered-by');

// --- Routes ---

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate and sanitize query parameters
  const limit = Math.min(Math.max(parseInt(req.query.limit, 10) || 10, 1), 100);
  const offset = Math.max(parseInt(req.query.offset, 10) || 0, 0);

  // In production, this would come from a database with parameterized queries
  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  res.json({
    data: users.slice(offset, offset + limit),
    pagination: { limit, offset, total: users.length },
  });
});

// --- 404 Handler ---
// Catch-all for undefined routes; prevents Express from returning a default HTML page
app.use((_req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// --- Global Error Handler ---
// Express requires all 4 parameters to treat this as an error-handling middleware
// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  // Log the full error internally for debugging
  console.error('Unhandled error:', err);

  // Never leak stack traces or internal details to the client
  res.status(err.status || 500).json({
    error:
      process.env.NODE_ENV === 'production'
        ? 'Internal Server Error'
        : err.message,
  });
});

if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
  });
}

module.exports = app;

