**4. No Helmet or security headers**
Missing standard HTTP security headers (X-Content-Type-Options, X-Frame-Options, CSP, etc.).

**5. No input sanitization on `/users`**
While it's currently static data, if this evolves to accept query params (e.g., `?search=`), there's no validation or sanitization in place.

**6. Port hardcoded, no graceful shutdown**
Port 3000 is hardcoded and there's no graceful shutdown handling for SIGTERM/SIGINT.

---

### Suggested Improved Version

```js
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();
const PORT = process.env.PORT || 3000;

// --- Security middleware ---

// Set secure HTTP headers
app.use(helmet());

// Parse JSON with a size limit to prevent large-payload DoS
app.use(express.json({ limit: '10kb' }));

// Rate limiting — prevent brute-force / abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// --- Routes ---

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate query params if accepting search/filter input
  const { search } = req.query;
  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  if (search) {
    // Whitelist allowed characters to prevent injection
    if (typeof search !== 'string' || search.length > 100 || !/^[a-zA-Z0-9\s@._-]+$/.test(search)) {
      return res.status(400).json({ error: 'Invalid search parameter' });
    }
    const filtered = users.filter(u =>
      u.name.toLowerCase().includes(search.toLowerCase())
    );
    return res.json(filtered);
  }

  res.json(users);
});

// --- 404 handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global error handler ---
// Must have 4 parameters so Express recognizes it as an error handler
app.use((err, req, res, next) => {
  // Log the full error server-side for debugging
  console.error('Unhandled error:', err.message);

  // Never leak stack traces or internal details to the client
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'
      : err.message,
  });
});

// --- Graceful startup and shutdown ---
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

process.on('SIGTERM', () => {
  console.log('SIGTERM received. Shutting down gracefully...');
  server.close(() => process.exit(0));
});

process.on('SIGINT', () => {
  console.log('SIGINT received. Shutting down gracefully...');
  server.close(() => process.exit(0));
});

